const cfg = $input.item.json;

// Attention à l'orthographe : "afriquecod" (français), pas "africacod" — confirmé par une
// requête réseau réelle capturée depuis manager.afriquecod.com.
const BASE = "https://api.afriquecod.com/api";
const ORIGIN = "https://manager.afriquecod.com";
const SUPABASE_URL = cfg.supabase_url;
const SUPABASE_SERVICE_ROLE_KEY = cfg.supabase_service_role_key;
const PER_PAGE = 100;
const UPSERT_BATCH_SIZE = 500;
const PAGE_DELAY_MS = 400; // petite pause entre pages pour rester sous la limite Cloudflare (~120 req)
// Fenêtre glissante (2026-07-14) : le rescan complet depuis 2025-07-01 à chaque exécution a fini
// par dépasser le timeout n8n de 300s (l'historique à reparcourir grandit chaque jour, sans borne
// haute). Un rescan complet unique a été fait manuellement (timeout augmenté pour l'occasion) ;
// désormais chaque exécution planifiée ne rescanne que les ROLLING_WINDOW_DAYS derniers jours —
// marge choisie par le CEO au-delà des délais de confirmation/livraison observés ("plusieurs
// semaines"), largement suffisante pour capter tout changement de statut sur une commande encore
// active, tout en gardant chaque run rapide.
const ROLLING_WINDOW_DAYS = 90;
const MIN_ORDER_DATE = new Date(Date.now() - ROLLING_WINDOW_DAYS * 24 * 60 * 60 * 1000)
  .toISOString()
  .slice(0, 10);

// L'API est derrière Cloudflare : un User-Agent "nu" (client HTTP par défaut) se fait
// bloquer plus facilement qu'un User-Agent de navigateur.
const USER_AGENT =
  "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36";

// Marché Congo sur le compte AfriqueCOD dédié (distinct du compte Coliscod Angola).
// Objet complet capturé depuis une requête réseau réelle — envoyé tel quel, sans
// supposer quels champs le backend valide ou non.
const COUNTRIES = [
  {
    id: 17,
    old_id: "65dfdf15de9227002ef02de4",
    name: "Congo",
    currency: "XAF",
    currency_exchange_rate: 1,
    flag: "CG",
    phone_code: null,
    timezone: "Africa/Brazzaville",
    created_at: "2024-06-29T12:44:04.000000Z",
    updated_at: "2024-06-29T12:44:04.000000Z",
    deleted_at: null,
  },
];

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function bodyPreview(body) {
  try {
    return JSON.stringify(body).slice(0, 500);
  } catch {
    return String(body).slice(0, 500);
  }
}

async function africodLogin() {
  const res = await this.helpers.httpRequest({
    method: "POST",
    url: `${BASE}/login`,
    headers: {
      "Content-Type": "application/json",
      Accept: "application/json",
      "User-Agent": USER_AGENT,
      Origin: ORIGIN,
      Referer: `${ORIGIN}/`,
    },
    body: { email: cfg.africod_congo_email, password: cfg.africod_congo_password },
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  if (res.statusCode < 200 || res.statusCode >= 300) {
    throw new Error(`POST /login → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
  }

  const token = res.body && res.body.token;
  if (!token) {
    throw new Error(`POST /login → 200 mais pas de champ token: ${bodyPreview(res.body)}`);
  }
  return token;
}

// Retry avec backoff sur 403/429 (Cloudflare / rate limit) — jusqu'à 3 tentatives.
async function fetchOrdersPage(token, country, page) {
  let attempt = 0;

  while (true) {
    const res = await this.helpers.httpRequest({
      method: "GET",
      url: `${BASE}/orders-paginated`,
      qs: { per_page: PER_PAGE, page, orders_type: "leads" },
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
        "User-Agent": USER_AGENT,
        "X-Selected-Country": JSON.stringify(country),
        Origin: ORIGIN,
        Referer: `${ORIGIN}/`,
      },
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    if (res.statusCode === 403 || res.statusCode === 429) {
      attempt += 1;
      if (attempt > 3) {
        throw new Error(`GET /orders-paginated (page ${page}) → HTTP ${res.statusCode} après 3 tentatives: ${bodyPreview(res.body)}`);
      }
      await sleep(1500 * attempt);
      continue;
    }

    if (res.statusCode < 200 || res.statusCode >= 300) {
      throw new Error(`GET /orders-paginated (page ${page}) → HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
    }

    return res.body;
  }
}

const allRows = [];
const errors = [];
const perCountry = [];

if (!cfg.africod_congo_email || !cfg.africod_congo_password) {
  errors.push({ country: "ALL", message: "africod_congo_email / africod_congo_password manquants dans le nœud 'Config'." });
} else {
  let token = null;

  // ─── 1. Login ──────────────────────────────────────────────────────────
  try {
    token = await africodLogin.call(this);
  } catch (err) {
    errors.push({ country: "ALL", message: `Login initial échoué — ${err.message}` });
  }

  // ─── 2. Pour chaque pays, paginer /orders-paginated jusqu'à la dernière page ───
  if (token) {
    for (const country of COUNTRIES) {
      let fetched = 0;
      let apiTotal = null;


      try {
        let page = 1;
        let lastPage = 1;

        do {
          const data = await fetchOrdersPage.call(this, token, country, page);
          const pagination = data.pagination || {};
          lastPage = pagination.last_page ?? 1;
          if (apiTotal === null) apiTotal = pagination.total ?? null;

          const pageRows = [];

          for (const o of data.orders || []) {
            const firstItem =
              Array.isArray(o.order_items) && o.order_items.length > 0 ? o.order_items[0] : null;
            const productName = firstItem?.product?.name ?? null;
            const agentName = o.confirmation_agent?.username ?? null;
            const orderDate = o.order_date ? String(o.order_date).slice(0, 10) : null;
            if (!orderDate || orderDate < MIN_ORDER_DATE) continue;

            pageRows.push({
              order_id: o.order_id,
              internal_id: o.id,
              country_id: country.id,
              country_name: o.country?.name ?? country.name,
              customer_name: o.customer_name ?? null,
              customer_phone: o.customer_phone_1 ?? null,
              customer_city: o.customer_city ?? null,
              total_price: o.total_price ?? 0,
              quantity: o.quantity ?? null,
              confirmation_status: o.confirmation_status?.name ?? null,
              shipping_status: o.shipping_status?.name ?? null,
              seller_payment_status: o.seller_payment_status ?? null,
              product_name: productName,
              confirmation_agent: agentName,
              order_date: orderDate,
              order_created_at: o.created_at ?? null,
              confirmed_at: o.confirmed_at ?? null,
              delivered_at: o.delivered_at ?? null,
            });
          }

          allRows.push(...pageRows);
          fetched += pageRows.length;

          page += 1;
          // Pause entre pages seulement s'il en reste — inutile d'attendre après la dernière.
          if (page <= lastPage) await sleep(PAGE_DELAY_MS);
        } while (page <= lastPage);
      } catch (err) {
        // Une erreur sur un pays ne doit pas empêcher les autres d'être synchronisés.
        errors.push({ country: country.name, message: err.message });
      }

      // Visible même sans erreur HTTP : si apiTotal vaut 0 (ou fetched reste à 0 alors
      // qu'apiTotal > 0), ça pointe vers un problème d'accès plutôt qu'un bug de code.
      perCountry.push({ country: country.name, apiTotal, fetched });
    }
  }
}

// ─── 3. Upsert en masse vers Supabase, par lots de 500 lignes ─────────────
// Chaque lot est tenté indépendamment : si l'un échoue, les suivants sont quand même envoyés.
// Dédup par order_id d'abord : la pagination Congo peut chevaucher deux pages (un agent
// confirme une commande pendant le scan complet, ce qui la fait bouger dans le tri de l'API),
// et on ne veut pas que la même commande apparaisse deux fois dans un même lot (Postgres refuse
// "ON CONFLICT DO UPDATE ... affect row a second time" dans ce cas — observé en production).
// On garde la dernière occurrence.
const dedupedRows = Array.from(new Map(allRows.map((r) => [r.order_id, r])).values());

let upserted = 0;

for (let i = 0; i < dedupedRows.length; i += UPSERT_BATCH_SIZE) {
  const batch = dedupedRows.slice(i, i + UPSERT_BATCH_SIZE);

  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: `${SUPABASE_URL}/rest/v1/africod_congo_leads`,
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_SERVICE_ROLE_KEY,
        Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
        Prefer: "resolution=merge-duplicates,return=minimal",
      },
      body: batch,
      json: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    if (res.statusCode < 200 || res.statusCode >= 300) {
      throw new Error(`HTTP ${res.statusCode}: ${bodyPreview(res.body)}`);
    }

    upserted += batch.length;
  } catch (err) {
    errors.push({ country: "SUPABASE_UPSERT", message: `lot ${i}-${i + batch.length}: ${err.message}` });
  }
}

return [
  {
    json: {
      synced_orders: upserted,
      countries: COUNTRIES.map((c) => c.name),
      perCountry,
      errors,
      finished_at: new Date().toISOString(),
    },
  },
];
